   109	static int
   110	eval_arrlen(Expr* expr)
   111	{
   112	  if (auto p = expr->dcst<IntegerLiteral>())
   113	    return p->val;
   114	
   115	  if (auto p = expr->dcst<DeclRefExpr>()) {
   116	    if (p->decl == nullptr)
   117	      ABORT();
   118	
   119	    auto var = p->decl->dcst<VarDecl>();
   120	    if (!var || !var->type->qual.const_)
   121	      ABORT(); // 数组长度必须是编译期常量
   122	
   123	    switch (var->type->spec) {
   124	      case Type::Spec::kChar:
   125	      case Type::Spec::kInt:
   126	      case Type::Spec::kLong:
   127	      case Type::Spec::kLongLong:
   128	        return eval_arrlen(var->init);
   129	
   130	      default:
   131	        ABORT(); // 长度表达式必须是数值类型
   132	    }
   133	  }
   134	
   135	  if (auto p = expr->dcst<UnaryExpr>()) {
   136	    auto sub = eval_arrlen(p->sub);
   137	
   138	    switch (p->op) {
   139	      case UnaryExpr::kPos:
   140	        return sub;
   141	
   142	      case UnaryExpr::kNeg:
   143	        return -sub;
   144	
   145	      default:
   146	        ABORT();
   147	    }
   148	  }
   149	
   150	  if (auto p = expr->dcst<BinaryExpr>()) {
   151	    auto lft = eval_arrlen(p->lft);
   152	    auto rht = eval_arrlen(p->rht);
   153	
   154	    switch (p->op) {
   155	      case BinaryExpr::kAdd:
   156	        return lft + rht;
   157	
   158	      case BinaryExpr::kSub:
   159	        return lft - rht;
   160	
   161	      default:
   162	        ABORT();
   163	    }
   164	  }
   165	
   166	  if (auto p = expr->dcst<InitListExpr>()) {
   167	    if (p->list.empty())
   168	      return 0;
   169	    return eval_arrlen(p->list[0]);
   170	  }
   171	
   172	  ABORT();
   173	}
