   175	std::pair<TypeExpr*, std::string>
   176	Ast2Asg::operator()(ast::DirectDeclaratorContext* ctx, TypeExpr* sub)
   177	{
   178	  if (auto p = ctx->Identifier())
   179	    return { sub, p->getText() };
   180	
   181	  if (ctx->LeftBracket()) {
   182	    auto arrayType = make<ArrayType>();
   183	    arrayType->sub = sub;
   184	
   185	    if (auto p = ctx->assignmentExpression())
   186	      arrayType->len = eval_arrlen(self(p));
   187	    else
   188	      arrayType->len = ArrayType::kUnLen;
   189	
   190	    return self(ctx->directDeclarator(), arrayType);
   191	  }
   192	
   193	  if (ctx->LeftParen()) {
   194	    auto funcType = make<FunctionType>();
   195	    funcType->sub = sub;
   196	
   197	    if (auto p = ctx->parameterList()) {
   198	      for (auto&& param : p->parameterDeclaration()) {
   199	        auto sq = self(param->declarationSpecifiers());
   200	        TypeExpr* paramTexp = nullptr;
   201	        std::string paramName;
   202	        if (param->declarator()) {
   203	          auto [texp, name] = self(param->declarator(), nullptr);
   204	          paramTexp = texp;
   205	          paramName = name;
   206	        }
   207	        auto paramType = make<Type>();
   208	        paramType->spec = sq.first;
   209	        paramType->qual = sq.second;
   210	        paramType->texp = paramTexp;
   211	        funcType->params.push_back(paramType);
   212	      }
   213	    }
   214	
   215	    // Return the function type; the name comes from the inner directDeclarator
   216	    // But we need to get the name from the innermost Identifier
   217	    // The structure is: directDeclarator LeftParen parameterList? RightParen
   218	    // We need to recurse into the inner directDeclarator to get the name
   219	    auto inner = ctx->directDeclarator();
   220	    if (inner) {
   221	      auto [innerTexp, name] = self(inner, funcType);
   222	      return { innerTexp, name };
   223	    }
   224	    return { funcType, "" };
   225	  }
   226	
   227	  ABORT();
   228	}
