   375	{
   376	  auto children = ctx->children;
   377	  auto sub = self(dynamic_cast<ast::PrimaryExpressionContext*>(children[0]));
   378	
   379	  // Check for function call: postfixExpression LeftParen argumentExpressionList? RightParen
   380	  unsigned idx = 1;
   381	  while (idx < children.size()) {
   382	    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[idx]);
